export type actionTemplatesLogicType = MakeLogicType<
    actionTemplatesLogicValues,
    actionTemplatesLogicActions,
    Record<string, any>,
    actionTemplatesLogicMeta
>

export const actionTemplatesLogic = kea<actionTemplatesLogicType>([
    path(['products', 'workflows', 'frontend', 'hogflows', 'actionTemplatesLogic']),
    connect(() => ({
        values: [teamLogic, ['currentTeamIdStrict']],
    })),
    actions({
        deleteActionTemplate: (id: string) => ({ id }),
    }),
    loaders(({ values }) => ({
        actionTemplates: [
            [] as HogFlowActionTemplateApi[],
            {
                loadActionTemplates: async () => {
                    const response = await hogFlowActionTemplatesList(String(values.currentTeamIdStrict))
                    return response.results
                },
                createActionTemplate: async (template: Partial<HogFlowActionTemplateApi>) => {
                    const created = await hogFlowActionTemplatesCreate(
                        String(values.currentTeamIdStrict),
                        template as HogFlowActionTemplateApi
                    )
                    lemonToast.success('Action template created')
                    return [...values.actionTemplates, created]
                },
                updateActionTemplate: async ({
                    id,
                    template,
                }: {
                    id: string
                    template: Partial<HogFlowActionTemplateApi>
                }) => {
                    const updated = await hogFlowActionTemplatesPartialUpdate(
                        String(values.currentTeamIdStrict),
                        id,
                        template
                    )
                    lemonToast.success('Action template updated')
                    return values.actionTemplates.map((t) => (t.id === id ? updated : t))
                },
            },
        ],
    })),
    listeners(({ values, actions }) => ({
        deleteActionTemplate: async ({ id }) => {
            try {
                // Soft-delete is a PATCH so the backend can reject it while the template is still in use.
                await hogFlowActionTemplatesPartialUpdate(String(values.currentTeamIdStrict), id, { deleted: true })
                lemonToast.success('Action template deleted')
                actions.loadActionTemplates()
            } catch (error: any) {
                lemonToast.error(error?.data?.deleted ?? error?.detail ?? 'Failed to delete action template')
            }
        },
    })),
    selectors({
        actionTemplatesByCatalogId: [
            (s) => [s.actionTemplates],
            (actionTemplates: HogFlowActionTemplateApi[]): Record<string, HogFlowActionTemplateApi[]> => {
                const byCatalogId: Record<string, HogFlowActionTemplateApi[]> = {}
                for (const template of actionTemplates) {
                    byCatalogId[template.template_id] = byCatalogId[template.template_id] ?? []
                    byCatalogId[template.template_id].push(template)
                }
                return byCatalogId
            },
        ],
        actionTemplatesById: [
            (s) => [s.actionTemplates],
            (actionTemplates: HogFlowActionTemplateApi[]): Record<string, HogFlowActionTemplateApi> =>
                Object.fromEntries(actionTemplates.map((t) => [t.id, t])),
        ],
    }),
    afterMount(({ actions }) => {
        actions.loadActionTemplates()
    }),
])
